<template>
  <div class="result-container">
    <div class="title-wrap">
      <h2 class="title">{{$route.query.keywords}}</h2>
      <span class="sub-title">找到{{total}}个结果</span>
    </div>
    <el-tabs v-model="activeIndex">
      <el-tab-pane label="歌曲" name="songs">
        <table class="el-table">
          <thead>
            <th></th>
            <th>音乐标题</th>
            <th>歌手</th>
            <th>专辑</th>
            <th>时长</th>
          </thead>
          <tbody>
            <tr class="el-table__row" v-for="(item,i) in songs" :key="item.id">
              <td>{{i+1}}</td>
              <td>
                <div class="song-wrap">
                  <div class="name-wrap">
                    <span class="iconfont icon-bofang1" @click="play(item.id)"></span>
                    <span>{{item.name}}</span>
                    <span class="iconfont icon-MV" @click="playMv(item.mvid)"></span>
                  </div>
                  <span>{{item.album.name}}</span>
                </div>
              </td>
              <td>{{item.artists[0].name}}</td>
              <td>{{item.name}}</td>
              <td>{{item.duration|getGapTime}}</td>
            </tr>
          </tbody>
        </table>
      </el-tab-pane>
      <el-tab-pane label="歌单" name="lists">
        <div class="items">
          <div class="item" v-for="item in playlists" :key="item.id">
            <div class="img-wrap">
              <div class="num-wrap">
                播放量:
                <span class="num">{{item.playCount|getCount}}</span>
              </div>
              <img :src="item.coverImgUrl" alt="" />
              <span class="iconfont icon-icon_play_default"></span>
            </div>
            <p class="name">{{item.name}}</p>
          </div>
        </div>
      </el-tab-pane>
      <el-tab-pane label="MV" name="MV">
        <div class="items mv">
          <div class="item" v-for="item in mvList" :key="item.id">
            <div class="img-wrap">
              <img :src="item.cover" alt="" />
              <span class="iconfont icon-icon_play_default" @click="playMv(item.id)"></span>
              <div class="num-wrap">
                <div class="iconfont icon-icon_play_default"></div>
                <div class="num">{{item.playCount|getCount}}</div>
              </div>
              <span class="time">{{item.duration|getGapTime}}</span>
            </div>
            <div class="info-wrap">
              <div class="name">{{item.name}}</div>
              <div class="singer">{{item.artistName}}</div>
            </div>
          </div>
        </div>
      </el-tab-pane>
    </el-tabs>
    <!-- 分页器 -->
    <el-pagination
      @current-change="handleCurrentChange"
      background
      layout="prev, pager, next"
      :total="total"
      :current-page="page"
      :page-size="5"
      :limit="10"
    >
    </el-pagination>
  </div>
</template>

<script>
import music from "@/api/music";
export default {
  name: "result",
  data() {
    return {
      activeIndex: "songs",
      total: 0,
      page: 1,
      type: 1,
      songs:[],
      playlists:[],
      mvList:[]
    };
  },
  watch: {
    activeIndex() {
      this.page = 1
      let type = 1;
      switch (this.activeIndex) {
        case "songs":
          type = 1;
          break;
        case "lists":
          type = 1000;
          break;
        case "MV":
          type = 1004;
          break;
        default:
          break;
      }
      this.goResultInfo(type)
    },
  },
  methods: {
    playMv(mvid){
      this.$router.push('/mv?id='+mvid)
    },
    async play(id){
      const res = await music.playMusic({
        params:{
          id
        }
      })
      // console.log(res)
      this.$parent.$data.url = res.data[0].url
    },
    handleCurrentChange(index) {
      this.page = index
      this.goResultInfo()
    },
    async goResultInfo(type=1) {
      const res = await music.searchInfo({
        params:{
          keywords: this.$route.query.keywords,
          limit: 10,
          offset: (this.page - 1) * 10,
          type
        }
      });
      // console.log(res)
      if(type==1){
        this.songs = res.result.songs
        this.total = res.result.songCount
      }else if(type==1000){
        this.playlists = res.result.playlists
        this.total = res.result.playlistCount
      }else{
        this.mvList = res.result.mvs
        this.total = res.result.mvCount
      }
    },
  },
  created() {
    this.goResultInfo()
  },
};
</script>

<style lang='scss'>
.result-container{
  .el-table__row{
    .song-wrap{
      .name-wrap{
        display: flex;
        align-items: center;
        .icon-bofang1{
          margin-right: 5px;
          &:hover{
            color: brown;
          }
        }
        .icon-MV{
          margin-left: 5px;
          color:#B60B0C ;
        }
      }
    }
  }
}
.icon{
  color: #B3B3B3;
}
</style>
